# ❌ ANTI-PATTERN: Regenerating context every request
class BatsmanAnalyzer:
    def analyze_performance(self, player_stats):
        system_prompt = f"You are a cricket analyst. {player_stats}. Analyze batting form."
        response = client.messages.create(
            model="claude-3.5-sonnet",
            system=system_prompt,  # Regenerated each time!
            messages=[{"role": "user", "content": "Is this player in form?"}]
        )
        return response

# ✅ BEST PRACTICE: Cache static context
class BatsmanAnalyzer:
    def __init__(self, player_stats):
        self.player_stats = player_stats
        self.system_blocks = [
            {
                "type": "text",
                "text": "You are a cricket analyst specializing in batting form assessment."
            },
            {
                "type": "text",
                "text": f"Player profile: {player_stats}",
                "cache_control": {"type": "ephemeral"}  # Cache this!
            }
        ]

    def analyze(self, query):
        response = client.messages.create(
            model="claude-3.5-sonnet",
            system=self.system_blocks,
            messages=[{"role": "user", "content": query}]
        )
        return response

# ✅ CHAIN-OF-THOUGHT for complex reasoning
response = client.messages.create(
    model="claude-3.5-sonnet",
    messages=[{
        "role": "user",
        "content": "Given these 5 recent matches for player X, predict their form trajectory. Think step by step."
    }]
)

# ✅ RAG PATTERN: Ground analysis in actual data
class MatchAnalyzer:
    def __init__(self, embedding_index):
        self.index = embedding_index  # Vector store of match records

    def analyze_with_evidence(self, query):
        # Retrieve relevant matches
        relevant_matches = self.index.search(query, top_k=5)
        context = "\n".join([m["summary"] for m in relevant_matches])

        response = client.messages.create(
            model="claude-3.5-sonnet",
            messages=[{
                "role": "user",
                "content": f"Based on these recent matches:\n{context}\n\nQuestion: {query}"
            }]
        )
        return response
